/**
 * Fixed-point math utilities (Q64.64 format) - TypeScript reference implementation.
 * These mirror the on-chain Tolk functions for off-chain computation and testing.
 */

/** Q64.64 fixed-point unit: 2^64 */
export const ONE = 2n ** 64n;

/** log2(e) in Q64.64 ≈ 1.4427 * 2^64 */
export const LOG2_E = 26613026195688644984n;

/** ln(2) in Q64.64 ≈ 0.6931 * 2^64 */
export const LN_2 = 12786308645202655660n;

/** Maximum safe exponent input (~3.4 * ONE) */
export const EXP_LIMIT = 62771017353866807638n;

/** Fee range denominator: 10^18 */
export const FEE_RANGE = 10n ** 18n;

/**
 * Fixed-point multiplication: (a * b) >> 64
 */
export function fixedMul(a: bigint, b: bigint): bigint {
  return (a * b) >> 64n;
}

/**
 * Fixed-point division: (a << 64) / b
 */
export function fixedDiv(a: bigint, b: bigint): bigint {
  if (b === 0n) throw new Error('Division by zero');
  return (a << 64n) / b;
}

/**
 * Binary logarithm in Q64.64: log2(x)
 * Uses iterative squaring (bit-by-bit refinement of the fractional part).
 */
export function fixedLog2(x: bigint): bigint {
  if (x <= 0n) throw new Error('log2 domain error: x must be > 0');

  // Compute integer part: find highest bit position relative to ONE
  let result = 0n;
  let val = x;

  // Integer part: how many doublings above or below ONE
  if (val >= ONE) {
    // Count how many times we can halve above ONE
    let temp = val;
    while (temp >= 2n * ONE) {
      temp >>= 1n;
      result += ONE;
    }
    val = temp; // val is now in [ONE, 2*ONE)
  } else {
    // val < ONE: result will be negative
    let temp = val;
    while (temp < ONE) {
      temp <<= 1n;
      result -= ONE;
    }
    val = temp; // val is now in [ONE, 2*ONE)
  }

  // Fractional part: iterative squaring
  // val is in [ONE, 2*ONE). We refine the fractional bits of log2.
  let bit = ONE >> 1n; // 0.5 in Q64.64
  for (let i = 0; i < 64; i++) {
    // Square val (in Q64.64): val = val * val / ONE
    val = (val * val) >> 64n;
    if (val >= 2n * ONE) {
      val >>= 1n;
      result += bit;
    }
    bit >>= 1n;
  }

  return result;
}

/**
 * Power of 2 in Q64.64: 2^x
 * Splits x into integer and fractional parts.
 * Integer part: bit shift. Fractional part: minimax polynomial approximation.
 */
export function fixedPow2(x: bigint): bigint {
  if (x === 0n) return ONE;

  // Handle negative exponents
  const negative = x < 0n;
  let absX = negative ? -x : x;

  // Split into integer and fractional parts
  const intPart = absX >> 64n; // integer part
  const fracPart = absX & ((1n << 64n) - 1n); // fractional part [0, ONE)

  // Compute 2^frac using Taylor series of 2^f = e^(f*ln2):
  // 2^f = 1 + c1*f + c2*f^2 + ... + c9*f^9
  // where c_k = (ln2)^k / k! in Q64.64
  //
  // Coefficients computed as: LN2^k / (k! * ONE^(k-1))
  const c1 = 12786308645202655660n; // ln(2) * 2^64
  const c2 = 4431396893595737425n;  // (ln2)^2/2! * 2^64
  const c3 = 1023870087579328453n;  // (ln2)^3/3! * 2^64
  const c4 = 177423166116318949n;   // (ln2)^4/4! * 2^64
  const c5 = 24596073471909060n;    // (ln2)^5/5! * 2^64
  const c6 = 2841449829983171n;     // (ln2)^6/6! * 2^64
  const c7 = 281363276907910n;      // (ln2)^7/7! * 2^64
  const c8 = 24378270262728n;       // (ln2)^8/8! * 2^64
  const c9 = 1877525477726n;        // (ln2)^9/9! * 2^64

  // Evaluate polynomial using Horner's method
  const f = fracPart;
  let fracResult = c9;
  fracResult = c8 + ((fracResult * f) >> 64n);
  fracResult = c7 + ((fracResult * f) >> 64n);
  fracResult = c6 + ((fracResult * f) >> 64n);
  fracResult = c5 + ((fracResult * f) >> 64n);
  fracResult = c4 + ((fracResult * f) >> 64n);
  fracResult = c3 + ((fracResult * f) >> 64n);
  fracResult = c2 + ((fracResult * f) >> 64n);
  fracResult = c1 + ((fracResult * f) >> 64n);
  fracResult = ONE + ((fracResult * f) >> 64n);

  // Combine: 2^x = 2^int * 2^frac
  let result = fracResult << intPart;

  if (negative) {
    // 2^(-x) = ONE^2 / 2^x = (ONE << 64) / result
    result = (ONE << 64n) / result;
  }

  return result;
}

/**
 * Natural exponential in Q64.64: e^x = 2^(x * log2(e))
 */
export function fixedExp(x: bigint): bigint {
  const xTimesLog2E = (x * LOG2_E) >> 64n;
  return fixedPow2(xTimesLog2E);
}

/**
 * Natural logarithm in Q64.64: ln(x) = log2(x) * ln(2)
 */
export function fixedLn(x: bigint): bigint {
  if (x <= 0n) throw new Error('ln domain error: x must be > 0');
  return (fixedLog2(x) * LN_2) >> 64n;
}

/**
 * Convert a floating-point number to Q64.64 fixed-point
 */
export function toFixed(x: number): bigint {
  return BigInt(Math.round(x * Number(ONE)));
}

/**
 * Convert a Q64.64 fixed-point number to floating-point
 */
export function fromFixed(x: bigint): number {
  return Number(x) / Number(ONE);
}
